const mail = items[0].json;

// Extract email from "Name <email>"
const extractEmail = (field) => {
  const match = field?.match(/<([^>]+)>/);
  return match ? match[1] : field;
};

// Decode basic HTML entities from snippet
const decodeHtml = (text = "") =>
  text
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&amp;/g, "&")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");

// Use snippet as body (best available in trigger)
const body = decodeHtml(mail.snippet);

return [
  {
    json: {
      from: extractEmail(mail.From),
      to: extractEmail(mail.To),
      body
    }
  }
];

const inputA = items[0].json;
const inputB = items[1].json;

return [
  {
    json: {
      ...inputA,
      ...inputB
    }
  }
];

