def encrypt(text, key):
    encrypted = []
    key_length = len(key)

    for i in range(len(text)):
        encrypted_char = ord(text[i]) ^ ord(key[i % key_length])
        encrypted.append(str(encrypted_char))

    return "-".join(encrypted)


