def decrypt(encrypted_text, key):
    decrypted = []
    key_length = len(key)
    parts = encrypted_text.split("-")

    for i in range(len(parts)):
        decrypted_char = chr(int(parts[i]) ^ ord(key[i % key_length]))
        decrypted.append(decrypted_char)

    return "".join(decrypted)


